export type IconName = keyof typeof iconMap;

export type IconProps = {
  name: IconName;
  size?: number;
  color?: string;
  style?: StyleProp<ViewStyle>;
  accessibilityLabel?: string;
  testID?: string;
};

export const iconNames = Object.keys(iconMap) as IconName[];

export function Icon({ name, size = theme.spacing.xl, color = theme.colors.content.ink, style, accessibilityLabel, testID }: IconProps) {
  const paths = figmaPaths[name as keyof typeof figmaPaths];

  if (paths) {
    return (
      <Svg width={size} height={size} viewBox="0 0 24 24" fill="none" style={style} accessibilityLabel={accessibilityLabel} testID={testID}>
        {paths.map((path) => {
          const pathData = typeof path === "string" ? path : path.d;
          const transform = typeof path === "string" ? undefined : path.transform;

          const fillRule = typeof path === "string" || !("fillRule" in path) ? undefined : path.fillRule;
          const clipRule = typeof path === "string" || !("clipRule" in path) ? undefined : path.clipRule;

          return <Path key={pathData} d={pathData} fill={color} transform={transform} fillRule={fillRule} clipRule={clipRule} />;
        })}
      </Svg>
    );
  }

  return <MaterialIcons name={iconMap[name]} size={size} color={color} accessibilityLabel={accessibilityLabel} testID={testID} />;
}
